export function getCountry(cid) {
  return WORLD_COUNTRIES.find(c => c.id === cid);
}
export function getToursByCountry(cid) {
  return WORLD_TOURS.filter(t => t.countrySlug === cid);
}
export function getWorldTour(slug) {
  return WORLD_TOURS.find(t => t.slug === slug);
}
export function getFeaturedWorldTours(limit = 12) {
  return WORLD_TOURS.filter(t => t.featured).slice(0, limit);
}
export function getTrendingWorldTours(limit = 12) {
  return WORLD_TOURS.filter(t => t.trending).slice(0, limit);
}
export function getCountriesByRegion(region) {
  return WORLD_COUNTRIES.filter(c => c.region === region);
}
